update store_warehouse_inventory_item
inventory_id = #{inventoryId}, spu_no = #{spuNo}, change_type = #{changeType}, unit = #{unit}, stock_lonely_quantity = #{stockLonelyQuantity}, stock_quantity = #{stockQuantity}, inventory_quantity = #{inventoryQuantity}, inventory_lonely_quantity = #{inventoryLonelyQuantity}, initial_inventory_cost = #{initialInventoryCost}, storage_amount = #{storageAmount}, inventory_status = #{inventoryStatus}, inventory_result = #{inventoryResult}, sales_quantity = #{salesQuantity}, sales_lonely_quantity = #{salesLonelyQuantity}, sales_amount = #{salesAmount}, remaining_quantity = #{remainingQuantity}, status = #{status}, price = #{price}, comment = #{comment}, create_time = #{createTime}, last_modify_time = #{lastModifyTime},
where item_id = #{itemId}

mapper.select:
SELECT t3.spu_no spuNo, t4.NAME spuName FROM store_goods_quotation t2, store_goods_quotation_goods t3, store_goods_spu t4 WHERE t2.dept_id = #{deptId} AND t2.STATUS = '1' AND t3.STATUS IN('1', '2') AND t2.quotation_id = t3.quotation_id AND t3.spu_no = t4.spu_no
AND t3.spu_no = #{spuNo}
GROUP BY t3.spu_no

SELECT t2.spu_no spuno, t3.sorting_quantity_unit unit, sum( t3.sorting_quantity ) salesLonelyQuantity, sum( t3.sorting_weight ) salesQuantity, sum( t2.sorting_price) price, avg( t2.sorting_price ) salesAmount FROM store_goods_order t1, store_goods_order_item t2, store_sorting_detail t3 WHERE t1.order_id = t2.order_id AND t3.status = '1'
AND t1.dept_id = #{deptId}
AND t2.spu_no = #{spuNo}
AND t1.STATUS IN ( '3', '4' ) AND t2.item_id = t3.order_item_id
AND t1.create_time >= #{startTime}
AND t1.create_time < #{endTime}
GROUP BY t2.spu_no, t3.sorting_quantity_unit

SELECT t.spu_no spuNo, t.main_case_sub mainCaseSub, t.sub_case_main subCaseMain, t1.main_unit_id mainUnitId, t1.sub_unit_id subUnitId FROM store_goods_spu_unit_conversion t, store_goods_spu_unit t1 WHERE dept_id = '0' AND t.spu_no = t1.spu_no
AND t.spu_no = #{spuNo}
AND NOT EXISTS ( SELECT spu_no FROM store_goods_spu_unit_conversion t2 WHERE t2.spu_no = t.spu_no AND dept_id = #{deptId} ) UNION ALL SELECT t.spu_no spuNo, t.main_case_sub mainCaseSub, t.sub_case_main subCaseMain, t1.main_unit_id mainUnitId, t1.sub_unit_id subUnitId FROM store_goods_spu_unit_conversion t, store_goods_spu_unit t1 WHERE dept_id = #{deptId} AND t.spu_no = t1.spu_no
AND t.spu_no = #{spuNo}

SELECT t2.spu_no spuno, sum(t2.quantity) stockQuantity, sum(t2.stocks_number) stockLonelyQuantity , sum(IFNULL(IFNULL(no_tax_price, total_price), 0.0)) price, avg(amount) storageAmount FROM store_warehouse_stock t1, store_warehouse_stock_item t2 WHERE t1.dept_id = #{deptId} AND t1.stock_id = t2.stock_id AND t2.status = '1' AND t1.status = '1'
AND t1.create_time >= #{startTime}
AND t1.create_time < #{endTime}
AND t1.warehouse_id = #{warehouseId}
AND t2.spu_no = #{spuNo}
AND t1.category != '6'
GROUP BY spu_no

SELECT t2.spu_no spuno, sum(t2.quantity) stockQuantity, sum(t2.stocks_number) stockLonelyQuantity , sum(IFNULL(IFNULL(no_tax_price, total_price), 0.0)) price, avg(amount) storageAmount FROM store_warehouse_stock t1, store_warehouse_stock_item t2 WHERE t1.dept_id = #{deptId} AND t1.stock_id = t2.stock_id AND t2.status = '1' AND t1.status = '1'
AND t1.create_time >= #{startTime}
AND t1.create_time < #{endTime}
AND t1.warehouse_id = #{warehouseId}
AND t2.spu_no = #{spuNo}
AND t1.category = '6' GROUP BY spu_no

SELECT t2.spu_no spuno, sum( t2.inventory_quantity ) inventoryquantity, sum( t2.inventory_lonely_quantity ) inventorylonelyquantity, sum( t2.inventory_result) inventoryresult FROM store_warehouse_inventory t1, store_warehouse_inventory_item t2 WHERE t1.dept_id = #{deptId} AND t1.inventory_id = t2.inventory_id AND t2.status = '1' AND t1.status = '1'
AND t1.intentory_date >= #{startTime}
AND t1.intentory_date <= #{endTime}
AND t1.warehouse_id = #{warehouseId}
AND t2.spu_no = #{spuNo}
GROUP BY spu_no

SELECT t2.spu_no spuno, IFNULL(sum(t2.src_sorting_weight - t2.old_sorting_weight), 0.0) salesQuantity FROM store_goods_order t1, store_goods_order_item t2 WHERE t1.order_id = t2.order_id
AND t1.dept_id = #{deptId}
AND t2.spu_no = #{spuNo}
AND t1.STATUS IN ( '3', '4' )
AND t1.create_time >= #{startTime}
AND t1.create_time < #{endTime}
GROUP BY t2.spu_no

SELECT
    t2.spu_no spuno,
    IFNULL(sum(t2.quantity - t2.real_quantity), 0.0) stockQuantity
FROM
    store_warehouse_stock t1,  store_warehouse_stock_item t2
WHERE t1.dept_id = #{deptId} AND t1.stock_id = t2.stock_id AND t2.status = '1' AND t1.status = '1'

    AND t1.create_time >= #{startTime}


    AND t1.create_time < #{endTime}


    AND t1.warehouse_id = #{warehouseId}


    AND t2.spu_no = #{spuNo}


    AND t1.category != '6'

GROUP BY spu_no
